INSERT INTO public.handover_task_templates (category, name, description, sort_order) VALUES
('Rota & Scheduling', 'Monitoring rota on care planning software', 'Monitor the live rota throughout the day to ensure visits to service users are not late or missed. Where a visit runs late, contact the service user and carer, and escalate to a manager where necessary.', 0),
('Rota & Scheduling', 'Creating or updating the staff rota', 'Build and amend the rota in response to new or changed visit times, cancellations and last-minute carer unavailability, ensuring continuity of care and appropriate skill mix.', 1),
('Rota & Scheduling', 'Monitoring late / missed visits (electronic call monitoring)', 'Use the electronic call monitoring (ECM) system to track real-time clock-in/out alerts, follow up on late or missed visits and record actions taken to safeguard service users.', 2),
('Rota & Scheduling', 'Managing the on-call rota and out-of-hours cover', 'Maintain the on-call schedule, brief on-call staff and ensure out-of-hours contact details and handover information are current and accessible.', 3),
('Rota & Scheduling', 'Managing carer availability, annual leave and absence', 'Record carer availability, process annual leave requests, log sickness/absence and update the rota accordingly to maintain safe staffing levels.', 4),
('Rota & Scheduling', 'Reconciling delivered hours against commissioned hours', 'Cross-check care hours actually delivered (via ECM) against hours commissioned by the local authority or private client to identify under/over-delivery before invoicing.', 5),
('Rota & Scheduling', 'Rota management', 'Issuing weekly rotas to staff and making changes as required', 6),
('Care Quality & Documentation', 'Completing forecast of stafing hours/ service user demand', NULL, 7),
('Care Quality & Documentation', 'Review care visit notes', 'Review carers'' visit notes the following day, verifying completeness, accuracy and quality, and following up any gaps, concerns or changes in need.', 8),
('Care Quality & Documentation', 'Reviewing care plans', 'Review care plans, or support the manager to do so, ensuring they are up to date, reflect current service user needs and preferences, and meet CQC documentation standards.', 9),
('Care Quality & Documentation', 'New service user onboarding / setting up care packages', 'Set up new service user records, gather assessment information, create the initial care plan and risk assessments, and confirm visit schedules and key information.', 10),
('Care Quality & Documentation', 'Updating service user records following change in need', 'Update care plans, risk assessments and records promptly when a service user''s needs, medication or circumstances change, and communicate changes to the care team.', 11),
('Care Quality & Documentation', 'Quality assurance / courtesy calls to service users', 'Make periodic courtesy or review calls to service users and families to check satisfaction with care delivery and capture any concerns or compliments.', 12),
('Care Quality & Documentation', 'Reviewing the risk register', 'Review and update the organisational risk register, ensuring identified risks have current mitigations, named owners and review dates.', 13),
('Care Quality & Documentation', 'Managing service user risk assessments', 'Maintain individual risk assessments (e.g. moving & handling, environmental, lone working) and ensure they are reviewed at the required intervals or after an incident.', 14),
('Care Quality & Documentation', 'Daily MAR chart / eMAR check', 'checking medication records for gaps or errors and ensure corrective actions and lessons learned are followed through.', 15),
('Care Quality & Documentation', 'Alerts Managements in Care Planning Software', 'Daily triage of app alerts (body maps, refusals, missed meds, flagged concerns).', 16),
('Communication', 'Answering phone calls from service users', 'Respond promptly and courteously to questions or concerns, escalate issues where needed and record outcomes where appropriate.', 17),
('Communication', 'Proffesional liason', 'Liaison with health/social care professionals (GPs, district nurses, social workers).', 18),
('Communication', 'Managing the company inbox and general correspondence', 'Monitor and triage the shared inbox, respond to or forward enquiries from professionals, families and staff, and keep correspondence appropriately filed.', 19),
('Training & Development', 'Monitoring expired training & allocating refreshers', 'Track training due dates, update training records and send reminders to staff for upcoming and overdue sessions.', 20),
('Training & Development', 'Assign mandatory and specialist training', 'Use the training system to allocate role-specific courses (e.g. Safeguarding, MCA, medication, moving & handling) in line with role requirements and CQC expectations.', 21),
('Training & Development', 'Monitoring Competency assessments', 'Ensuring the competency assessments are completed for all staff', 22),
('Training & Development', 'Supporting staff induction', 'Prepare welcome packs, organise the induction schedule (including Care Certificate where applicable) and ensure all mandatory paperwork is completed.', 23),
('Training & Development', 'Carrying out supervisions and annual appraisals', 'Support scheduling and documentation of staff supervisions (approx. every 2 months) and annual appraisals, preparing forms and collating feedback.', 24),
('Training & Development', 'Managing probation reviews,', NULL, 25),
('Training & Development', 'Monitoring staff spot checks', 'Track due dates and record outcomes of staff spot checks (approx. every 6 months) to ensure care delivery meets expected standards.', 26),
('Training & Development', 'Booking external/face-to-face training (manual handling, first aid).', NULL, 27),
('Incidents & Safeguarding', 'Create incident reports', 'Log incidents and accidents accurately and promptly in line with company policy, ensuring correct information is available for investigation and reporting.', 28),
('Incidents & Safeguarding', 'Recording and progressing safeguarding referrals', 'Record safeguarding concerns, support timely referral to the local authority safeguarding team and track the progress and outcome of each referral.', 29),
('Incidents & Safeguarding', 'Maintaining incident/ acident log', 'Keep the accident book up to date and flag any reportable events under RIDDOR to the manager for onward reporting where required.', 30),
('Audits & Governance', 'Completing audits', 'Assist managers in gathering and organising evidence for internal and external audits (e.g. CQC), including policies, training records and care documentation.', 31),
('Meetings', 'Scheduling, attending and minuting staff meetings', 'Prepare agendas, take attendance and write minutes to ensure team communication is consistent and documented.', 32),
('Meetings', 'Coordinating and minuting management meetings', 'Coordinate attendance, share reminders, ensure the team join the management meeting, and record accurate minutes and actions.', 33),
('Recruitment & HR', 'Advertising for roles and interviewing candidates', 'Post job adverts, manage applicant responses, book interviews and prepare interview packs.', 34),
('Recruitment & HR', 'completing safer recruitment checks', 'complete the full suite of pre-employment safer recruitment checks.', 35),
('Recruitment & HR', 'DBS tracking and update-service checks — initial checks plus diarised renewals.', 'initial checks plus diarised renewals.', 36),
('Recruitment & HR', 'Right to work / sponsored worker compliance —', 'share-code verification post-BRP, sponsor licence record-keeping.', 37),
('Compliance & Policies', 'Ensuring staff read policies and procedures', 'Issue updated policies to staff and record sign-offs to evidence understanding and compliance.', 38),
('Compliance & Policies', 'Records management, filing and retention', 'Maintain orderly filing of service user and staff records and apply the organisation''s retention and secure disposal schedule.', 39),
('Health & Safety / Emergency', 'Monitoring PPE levels', 'Monitor stock levels of PPE (gloves, aprons, masks, hand sanitiser), reorder before depletion and ensure carers can access adequate supplies in line with infection prevention and control.', 40),
('Health & Safety / Emergency', 'Business continuity plan', 'Support updates and reviews of the business continuity plan, ensuring emergency protocols and contact lists are current and accessible in line with the emergency planning policy.', 41),
('Health & Safety / Emergency', 'Tracking equipment servicing and maintenance', 'Maintain a log of care equipment and ensure servicing, inspection and maintenance (e.g. LOLER/PUWER for hoists) is scheduled and recorded.', 42),
('Finance / Payroll', 'Completing payroll / processing timesheets', 'Collate and verify timesheets or ECM-confirmed hours, calculate pay, mileage and any deductions, and submit accurate data for payroll processing.', 43),
('Finance / Payroll', 'Invoicing local authority and private clients', 'Generate and issue invoices for delivered care, reconcile against commissioned hours and follow up on outstanding payments.', 44),
('Finance / Payroll', 'Processing mileage and expense claims', 'Check and process staff mileage and expense claims against policy and submit for reimbursement.', 45),
('Finance / Payroll', 'Ordering office supplies and stationery', 'Monitor and reorder office consumables, care documentation stock and stationery to keep operations running smoothly.', 46),
('Feedback & Engagement', 'Collating service user & staff feedback', 'Gather feedback through surveys, reviews, compliments and complaints; collate results for analysis and reporting to inform service improvement.', 47),
('Feedback & Engagement', 'Managing the complaints and compliments log', 'Record complaints and compliments, track them through to resolution within policy timescales and identify themes for learning.', 48);